const allItems = $input.all();
const webhookBody = allItems[0]?.json?.body || allItems[0]?.json || {};
const isWebhook = !!(webhookBody.scanType || webhookBody.software);

// Build asset inventory from Airtable
const assets = allItems
  .filter(i => i.json.fields?.['Asset ID'])
  .map(i => {
    const f = i.json.fields;
    return {
      assetId: f['Asset ID'],
      hostname: f['Hostname'] || '',
      ipAddress: f['IP Address'] || '',
      assetType: f['Asset Type'] || 'Server',
      os: f['Operating System'] || '',
      osVersion: f['OS Version'] || '',
      software: (f['Software'] || '').split(',').map(s => s.trim()).filter(Boolean),
      softwareVersion: (f['Software Version'] || '').split(',').map(s => s.trim()).filter(Boolean),
      vendor: f['Vendor'] || '',
      environment: f['Environment'] || 'Production',
      internetFacing: f['Internet Facing'] === true || f['Internet Facing'] === 'Yes',
      criticality: f['Criticality'] || 'MEDIUM',
      owner: f['Owner'] || '',
      lastPatched: f['Last Patched'] || null
    };
  });

// Demo assets if none loaded
const demoAssets = assets.length > 0 ? assets : [
  { assetId: 'ASSET-001', hostname: 'web-prod-01', ipAddress: '203.0.113.10', assetType: 'Web Server', os: 'Ubuntu', osVersion: '22.04', software: ['Apache HTTP Server', 'OpenSSL', 'PHP'], softwareVersion: ['2.4.54', '3.0.2', '8.1.12'], vendor: 'Apache Software Foundation', environment: 'Production', internetFacing: true, criticality: 'CRITICAL', owner: 'user@example.com', lastPatched: '2024-11-01' },
  { assetId: 'ASSET-002', hostname: 'db-prod-01', ipAddress: '10.0.1.5', assetType: 'Database Server', os: 'CentOS', osVersion: '7.9', software: ['MySQL', 'OpenSSH'], softwareVersion: ['8.0.31', '7.4p1'], vendor: 'Oracle', environment: 'Production', internetFacing: false, criticality: 'CRITICAL', owner: 'user@example.com', lastPatched: '2024-10-15' },
  { assetId: 'ASSET-003', hostname: 'k8s-master-01', ipAddress: '10.0.2.1', assetType: 'Container Orchestrator', os: 'Ubuntu', osVersion: '20.04', software: ['Kubernetes', 'Docker', 'containerd'], softwareVersion: ['1.26.0', '24.0.5', '1.6.20'], vendor: 'CNCF', environment: 'Production', internetFacing: false, criticality: 'HIGH', owner: 'user@example.com', lastPatched: '2024-09-20' },
  { assetId: 'ASSET-004', hostname: 'vpn-gateway-01', ipAddress: '203.0.113.20', assetType: 'Network Appliance', os: 'FortiOS', osVersion: '7.2.4', software: ['FortiGate', 'FortiSSL'], softwareVersion: ['7.2.4', '7.2.4'], vendor: 'Fortinet', environment: 'Production', internetFacing: true, criticality: 'CRITICAL', owner: 'user@example.com', lastPatched: '2024-08-30' }
];

const finalAssets = demoAssets;

// Build search terms from asset inventory
const searchTerms = [];
for (const asset of finalAssets) {
  searchTerms.push(asset.os + ' ' + asset.osVersion);
  for (let i = 0; i < asset.software.length; i++) {
    searchTerms.push(asset.software[i]);
    if (asset.softwareVersion[i]) searchTerms.push(asset.software[i] + ' ' + asset.softwareVersion[i]);
  }
}
const uniqueTerms = [...new Set(searchTerms.filter(Boolean))];

// Also include webhook-specified software if provided
if (isWebhook && webhookBody.software) {
  uniqueTerms.unshift(webhookBody.software + (webhookBody.version ? ' ' + webhookBody.version : ''));
}

const scanRunId = `SCAN-${Date.now()}-${Math.random().toString(36).substr(2,5).toUpperCase()}`;

return [{
  json: {
    assets: finalAssets,
    searchTerms: uniqueTerms.slice(0, 20),
    scanRunId,
    scanType: isWebhook ? (webhookBody.scanType || 'targeted') : 'scheduled',
    requestedBy: webhookBody.requestedBy || 'system',
    scanStartedAt: new Date().toISOString()
  }
}];

const items = $input.all();
const scanContext = $('Build Scan Context & Search Terms').first().json;
const { assets, searchTerms, scanRunId } = scanContext;

// ── Parse NVD Results ──
const nvdRaw = $('Query NVD CVE Database').first()?.json || {};
const nvdCVEs = (nvdRaw.vulnerabilities || []).map(v => {
  const cve = v.cve || {};
  const metrics = cve.metrics?.cvssMetricV31?.[0] || cve.metrics?.cvssMetricV30?.[0] || {};
  const cvssData = metrics.cvssData || {};
  return {
    cveId: cve.id || '',
    source: 'NVD',
    description: cve.descriptions?.find(d => d.lang === 'en')?.value || '',
    cvssScore: cvssData.baseScore || 0,
    cvssVector: cvssData.vectorString || '',
    severity: cvssData.baseSeverity || metrics.baseSeverity || 'UNKNOWN',
    publishedDate: cve.published || '',
    lastModified: cve.lastModified || '',
    affectedProducts: (cve.configurations || []).flatMap(c =>
      c.nodes?.flatMap(n => n.cpeMatch?.map(m => m.criteria) || []) || []
    ).slice(0, 10),
    references: (cve.references || []).map(r => r.url).slice(0, 3),
    patchAvailable: (cve.references || []).some(r => r.tags?.includes('Patch') || r.tags?.includes('Vendor Advisory')),
    cisaKev: false,
    epssScore: null
  };
});

// ── Parse CISA KEV ──
const cisaRaw = $('Fetch CISA Known Exploited Vulns').first()?.json || {};
const kevSet = new Set();
const kevDetails = {};
for (const v of (cisaRaw.vulnerabilities || [])) {
  kevSet.add(v.cveID);
  kevDetails[v.cveID] = {
    vendorProject: v.vendorProject,
    product: v.product,
    vulnerabilityName: v.vulnerabilityName,
    dateAdded: v.dateAdded,
    requiredAction: v.requiredAction,
    dueDate: v.dueDate
  };
}

// ── Parse GitHub Advisories ──
const ghRaw = $('Query GitHub Security Advisories').first()?.json || [];
const ghCVEs = (Array.isArray(ghRaw) ? ghRaw : []).map(a => ({
  cveId: a.cve_id || a.ghsa_id || '',
  source: 'GitHub',
  description: a.summary || a.description || '',
  cvssScore: a.cvss?.score || 0,
  cvssVector: a.cvss?.vector_string || '',
  severity: (a.severity || 'UNKNOWN').toUpperCase(),
  publishedDate: a.published_at || '',
  lastModified: a.updated_at || '',
  affectedProducts: (a.vulnerabilities || []).map(v => `${v.package?.ecosystem}:${v.package?.name}@${v.vulnerable_version_range}`).slice(0, 5),
  references: [a.html_url || ''].filter(Boolean),
  patchAvailable: !!(a.vulnerabilities?.[0]?.patched_versions),
  cisaKev: false,
  epssScore: null
}));

// ── Parse EPSS Scores ──
const epssRaw = $('Fetch EPSS Exploit Probability Scores').first()?.json || {};
const epssMap = {};
for (const e of (epssRaw.data || [])) {
  epssMap[e.cve] = parseFloat(e.epss);
}

// ── Parse OTX Pulses for CVE mentions ──
const otxRaw = $('Fetch AlienVault OTX Pulses').first()?.json || {};
const otxCveIds = new Set();
for (const pulse of (otxRaw.results || [])) {
  for (const tag of (pulse.tags || [])) {
    if (/CVE-\d{4}-\d{4,}/i.test(tag)) otxCveIds.add(tag.toUpperCase());
  }
  const cveRefs = (pulse.references || []).filter(r => /CVE-\d{4}-\d{4,}/i.test(r));
  for (const r of cveRefs) {
    const m = r.match(/CVE-\d{4}-\d{4,}/i);
    if (m) otxCveIds.add(m[0].toUpperCase());
  }
}

// ── Merge & Deduplicate ──
const allCVEs = [...nvdCVEs, ...ghCVEs];
const cveMap = {};
for (const cve of allCVEs) {
  if (!cve.cveId) continue;
  const id = cve.cveId.toUpperCase();
  if (!cveMap[id] || (cve.cvssScore > (cveMap[id].cvssScore || 0))) {
    cveMap[id] = {
      ...cve,
      cveId: id,
      cisaKev: kevSet.has(id),
      kevDetails: kevDetails[id] || null,
      epssScore: epssMap[id] || null,
      activelyExploited: kevSet.has(id) || otxCveIds.has(id),
      otxMentioned: otxCveIds.has(id)
    };
  }
}

// Add high-EPSS CVEs not yet in map
for (const [cveId, epss] of Object.entries(epssMap)) {
  if (!cveMap[cveId] && epss > 0.7) {
    cveMap[cveId] = {
      cveId, source: 'EPSS', description: 'High exploit probability — check NVD for details',
      cvssScore: 0, severity: 'UNKNOWN', publishedDate: '', affectedProducts: [],
      references: [`https://nvd.nist.gov/vuln/detail/${cveId}`],
      patchAvailable: false, cisaKev: kevSet.has(cveId),
      kevDetails: kevDetails[cveId] || null,
      epssScore: epss, activelyExploited: kevSet.has(cveId) || otxCveIds.has(cveId), otxMentioned: otxCveIds.has(cveId)
    };
  }
}

// ── Asset Correlation ──
const softwareKeywords = assets.flatMap(a => [
  ...a.software.map(s => s.toLowerCase()),
  a.os.toLowerCase(),
  a.vendor.toLowerCase()
].filter(Boolean));

const correlatedThreats = [];
for (const cve of Object.values(cveMap)) {
  // Match CVE to assets
  const matchedAssets = [];
  const descLower = cve.description.toLowerCase();
  const productsLower = cve.affectedProducts.map(p => p.toLowerCase()).join(' ');
  const searchText = descLower + ' ' + productsLower;

  for (const asset of assets) {
    let matched = false;
    for (const sw of asset.software) {
      if (searchText.includes(sw.toLowerCase()) || sw.toLowerCase().split(' ').some(w => w.length > 3 && searchText.includes(w))) {
        matched = true;
        break;
      }
    }
    if (!matched && (searchText.includes(asset.os.toLowerCase()) || searchText.includes(asset.vendor.toLowerCase()))) matched = true;
    if (matched) matchedAssets.push({ assetId: asset.assetId, hostname: asset.hostname, criticality: asset.criticality, internetFacing: asset.internetFacing, environment: asset.environment });
  }

  // Only include CVEs that match assets OR are CISA KEV / EPSS > 0.8
  if (matchedAssets.length > 0 || cve.cisaKev || (cve.epssScore || 0) > 0.8) {
    correlatedThreats.push({ ...cve, matchedAssets, assetMatchCount: matchedAssets.length });
  }
}

// Sort by severity composite
const sev = (c) => {
  let score = c.cvssScore * 8;
  if (c.cisaKev) score += 25;
  if (c.activelyExploited) score += 20;
  if ((c.epssScore || 0) > 0.7) score += 15;
  if (c.assetMatchCount > 0) score += 10;
  return score;
};
correlatedThreats.sort((a, b) => sev(b) - sev(a));

// Demo threats if nothing found
const demoThreats = correlatedThreats.length > 0 ? correlatedThreats : [
  { cveId: 'CVE-2024-38856', source: 'NVD', description: 'Apache OFBiz before 18.12.15 is vulnerable to pre-authentication remote code execution via the ViewHandlerExt endpoint, allowing unauthenticated attackers to execute arbitrary code.', cvssScore: 9.8, cvssVector: 'CVSS:3.1/AV:N/AC:L/PR:N/UI:N/S:U/C:H/I:H/A:H', severity: 'CRITICAL', publishedDate: '2024-08-05', affectedProducts: ['cpe:2.3:a:apache:ofbiz:*:*:*:*:*:*:*:*'], references: ['https://nvd.nist.gov/vuln/detail/CVE-2024-38856'], patchAvailable: true, cisaKev: true, kevDetails: { product: 'Apache OFBiz', requiredAction: 'Apply mitigations per vendor instructions', dueDate: '2024-08-28' }, epssScore: 0.94, activelyExploited: true, otxMentioned: true, matchedAssets: [{ assetId: 'ASSET-001', hostname: 'web-prod-01', criticality: 'CRITICAL', internetFacing: true, environment: 'Production' }], assetMatchCount: 1 },
  { cveId: 'CVE-2024-21762', source: 'NVD', description: 'Fortinet FortiOS out-of-bounds write vulnerability in sslvpnd allows a remote unauthenticated attacker to execute arbitrary code or commands via specially crafted HTTP requests.', cvssScore: 9.6, cvssVector: 'CVSS:3.1/AV:N/AC:L/PR:N/UI:N/S:U/C:H/I:H/A:H', severity: 'CRITICAL', publishedDate: '2024-02-09', affectedProducts: ['cpe:2.3:o:fortinet:fortios:*:*:*:*:*:*:*:*'], references: ['https://nvd.nist.gov/vuln/detail/CVE-2024-21762'], patchAvailable: true, cisaKev: true, kevDetails: { product: 'Fortinet FortiOS', requiredAction: 'Apply mitigations per vendor instructions or disable SSL VPN', dueDate: '2024-02-16' }, epssScore: 0.97, activelyExploited: true, otxMentioned: true, matchedAssets: [{ assetId: 'ASSET-004', hostname: 'vpn-gateway-01', criticality: 'CRITICAL', internetFacing: true, environment: 'Production' }], assetMatchCount: 1 },
  { cveId: 'CVE-2024-6387', source: 'NVD', description: 'OpenSSH regreSSHion: A signal handler race condition in sshd(8) on glibc-based Linux systems allows unauthenticated remote code execution as root. Regression of CVE-2006-5051.', cvssScore: 8.1, cvssVector: 'CVSS:3.1/AV:N/AC:H/PR:N/UI:N/S:U/C:H/I:H/A:H', severity: 'HIGH', publishedDate: '2024-07-01', affectedProducts: ['cpe:2.3:a:openbsd:openssh:*:*:*:*:*:*:*:*'], references: ['https://nvd.nist.gov/vuln/detail/CVE-2024-6387'], patchAvailable: true, cisaKev: false, kevDetails: null, epssScore: 0.88, activelyExploited: true, otxMentioned: false, matchedAssets: [{ assetId: 'ASSET-002', hostname: 'db-prod-01', criticality: 'CRITICAL', internetFacing: false, environment: 'Production' }], assetMatchCount: 1 }
];

return [{
  json: {
    scanRunId,
    assets,
    scanContext,
    threats: demoThreats,
    stats: {
      totalCVEsFound: Object.keys(cveMap).length || demoThreats.length,
      correlatedToAssets: demoThreats.filter(t => t.assetMatchCount > 0).length,
      cisaKevCount: demoThreats.filter(t => t.cisaKev).length,
      activelyExploited: demoThreats.filter(t => t.activelyExploited).length,
      highEPSS: demoThreats.filter(t => (t.epssScore || 0) > 0.7).length
    },
    normalisedAt: new Date().toISOString()
  }
}];

const aiResp = $input.item.json;
let aiText = aiResp.response || aiResp.output || aiResp.text || '';
if (aiResp.content && Array.isArray(aiResp.content)) aiText = aiResp.content[0]?.text || '';

const clean = aiText.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();
let assessment;
try {
  assessment = JSON.parse(clean);
} catch(e) {
  const m = clean.match(/\{[\s\S]*\}/);
  try { assessment = m ? JSON.parse(m[0]) : null; } catch(e2) { assessment = null; }
  if (!assessment) {
    assessment = {
      overallThreatLevel: 'HIGH',
      executiveSummary: 'Threat assessment processing error — manual review required.',
      threatAssessments: [], immediateActionRequired: true,
      topPriorityThreats: [], globalRemediationPriority: ['Review raw CVE data manually'],
      threatLandscapeSummary: 'Unable to complete automated assessment.'
    };
  }
}

const upstream = $('Normalise, Deduplicate & Correlate').first().json;

// Sort by urgency score
const sorted = (assessment.threatAssessments || []).sort((a,b) => (b.urgencyScore||0) - (a.urgencyScore||0));

const criticalCount = sorted.filter(t => t.severity === 'CRITICAL').length;
const highCount = sorted.filter(t => t.severity === 'HIGH').length;
const activelyExploitedCount = sorted.filter(t => t.isActivelyExploited).length;
const kevCount = sorted.filter(t => t.isCisaKev).length;
const patchAvailableCount = sorted.filter(t => t.patchAvailable).length;

return {
  json: {
    scanRunId: upstream.scanRunId,
    scanContext: upstream.scanContext,
    assets: upstream.assets,
    rawThreats: upstream.threats,
    assessment: { ...assessment, threatAssessments: sorted },
    summary: {
      overallThreatLevel: assessment.overallThreatLevel,
      totalAssessed: sorted.length,
      criticalCount, highCount,
      mediumCount: sorted.filter(t => t.severity === 'MEDIUM').length,
      lowCount: sorted.filter(t => t.severity === 'LOW').length,
      activelyExploitedCount, kevCount, patchAvailableCount,
      immediateActionRequired: assessment.immediateActionRequired
    },
    criticalAndHighThreats: sorted.filter(t => ['CRITICAL','HIGH'].includes(t.severity)),
    assessedAt: new Date().toISOString()
  }
};

