}

parameters.jsCode:
// Create one Jira ticket per CRITICAL/HIGH threat
const d = $input.item.json;
const threats = d.criticalAndHighThreats.slice(0, 5); // top 5
const results = [];

for (const threat of threats) {
  results.push({
    json: {
      jiraPayload: {
        fields: {
          project: { key: 'SEC' },
          issuetype: { name: 'Vulnerability' },
          summary: `[${threat.severity}] ${threat.cveId} — ${threat.threatName}`,
          priority: { name: threat.severity === 'CRITICAL' ? 'Highest' : 'High' },
          description: {
            type: 'doc', version: 1,
            content: [
              { type: 'paragraph', content: [{ type: 'text', text: `CVE: ${threat.cveId} | CVSS: ${threat.cvssScore} | EPSS: ${((threat.epssScore||0)*100).toFixed(1)}% | Urgency: ${threat.urgencyScore}/100` }] },
              { type: 'paragraph', content: [{ type: 'text', text: `Impact: ${threat.impactType} | Exploit Maturity: ${threat.exploitMaturity}` }] },
              { type: 'paragraph', content: [{ type: 'text', text: `Affected Assets: ${(threat.affectedAssets||[]).join(', ')}` }] },
              { type: 'paragraph', content: [{ type: 'text', text: `CISA KEV: ${threat.isCisaKev} | Actively Exploited: ${threat.isActivelyExploited}` }] },
              { type: 'paragraph', content: [{ type: 'text', text: `Summary: ${threat.threatSummary}` }] },
              { type: 'paragraph', content: [{ type: 'text', text: `Immediate Action: ${(threat.immediateActions||[]).join(' | ')}` }] },
              { type: 'paragraph', content: [{ type: 'text', text: `Patch URL: ${threat.patchURL || 'See vendor advisory'}` }] }
            ]
          },
          labels: ['zero-day', 'vulnerability', threat.severity.toLowerCase(), threat.isCisaKev ? 'cisa-kev' : 'new-threat']
        }
      },
      cveId: threat.cveId,
      severity: threat.severity,
      scanRunId: d.scanRunId
    }
  });
}

return results.length > 0 ? results : [{ json: { skip: true, reason: 'No CRITICAL/HIGH threats for ticketing', scanRunId: d.scanRunId } }];

const d = $input.item.json;
return {
  json: {
    success: true,
    scanRunId: d.scanRunId,
    timestamp: d.assessedAt,
    overallThreatLevel: d.summary.overallThreatLevel,
    immediateActionRequired: d.summary.immediateActionRequired,
    summary: d.summary,
    executiveSummary: d.assessment.executiveSummary,
    topPriorityThreats: (d.assessment.topPriorityThreats || []),
    criticalThreats: d.criticalAndHighThreats.filter(t => t.severity === 'CRITICAL').map(t => ({
      cveId: t.cveId, threatName: t.threatName, urgencyScore: t.urgencyScore,
      cvssScore: t.cvssScore, epssScore: t.epssScore, isCisaKev: t.isCisaKev,
      affectedAssets: t.affectedAssets, impactType: t.impactType,
      exploitMaturity: t.exploitMaturity, patchAvailable: t.patchAvailable,
      patchURL: t.patchURL, immediateActions: t.immediateActions,
      mitreTechniques: t.mitreTechniques
    })),
    highThreats: d.criticalAndHighThreats.filter(t => t.severity === 'HIGH').map(t => ({
      cveId: t.cveId, threatName: t.threatName, urgencyScore: t.urgencyScore,
      cvssScore: t.cvssScore, affectedAssets: t.affectedAssets, impactType: t.impactType
    })),
    globalRemediationPriority: d.assessment.globalRemediationPriority,
    threatLandscapeSummary: d.assessment.threatLandscapeSummary
  }
};
